import subprocess
import shlex
import os

def convertDocument(input_file, output_file, output_format):
    # Validate file paths
    if not os.path.isfile(input_file):
        raise ValueError("Input file does not exist.")
    
    # Sanitize input to prevent command injection
    input_file = shlex.quote(input_file)
    output_file = shlex.quote(output_file)
    output_format = shlex.quote(output_format)
    
    # Construct the command
    command = f"libreoffice --headless --convert-to {output_format} --outdir {os.path.dirname(output_file)} {input_file}"
    
    # Execute the command
    subprocess.run(command, shell=True, check=True)

